package org.taskscheduler;

public class TaskExecuter extends Thread {

    private final Task task;
    private final TaskSchedulerConfig taskSchedulerConfig;

    public TaskExecuter(final Task task, final TaskSchedulerConfig taskSchedulerConfig) {
        this.task = task;
        this.taskSchedulerConfig = taskSchedulerConfig;
    }


    @Override
    public void run() {
        System.out.println("Running task " + this.task);
        try {
            System.out.printf("Started working on task %s at %d, will take %d seconds\n", this.task.getTaskName(), System.currentTimeMillis() / 1000, this.task.getDuration());
            Thread.sleep(this.task.getDuration() * 1000L);
            System.out.printf("Completed task %s at %d\n", this.task.getTaskName(), System.currentTimeMillis() / 1000);
        } catch (InterruptedException e) {
            throw new RuntimeException(e);
        } finally {
            // Update concurrency after task completion
            synchronized (taskSchedulerConfig) {
                taskSchedulerConfig.incrementConcurrency();
                taskSchedulerConfig.notify();
            }
        }
    }
}

