package org.taskscheduler;

import java.util.Comparator;
import java.util.LinkedList;
import java.util.PriorityQueue;
import java.util.Queue;

public class TaskScheduler extends Thread {
    private final TaskSchedulerConfig taskSchedulerConfig;
    private final Queue<Task> tasks;
    private final PriorityQueue<Task> scheduledTasks;

    public TaskScheduler(final TaskSchedulerConfig taskSchedulerConfig) {
        this.taskSchedulerConfig = taskSchedulerConfig;
        this.tasks = new LinkedList<>();
        this.scheduledTasks = new PriorityQueue<>(Comparator.comparingLong(Task::getScheduledTime));
    }

    public void addTask(final Task task) {
        System.out.println("Adding task: " + task);
        if ("AD_HOC".equals(task.getTaskType())) {
            tasks.offer(task);
        } else if ("SCHEDULED".equals(task.getTaskType())) {
            scheduledTasks.offer(task);
        } else {
            throw new RuntimeException("Unknown task type");
        }
        System.out.println("Scheduled tasks after adding: " + scheduledTasks);
        System.out.println("Ad Hoc tasks after adding: " + tasks);
        System.out.println();
    }

    @Override
    public void run() {
        try {
            synchronized (this.taskSchedulerConfig) {
                while (true) {
                    System.out.println("Available concurrency " + taskSchedulerConfig);
                    if (taskSchedulerConfig.getConcurrency() <= 0) {
                        System.out.println("Concurrency not available, waiting");
                        taskSchedulerConfig.wait();
                        System.out.println("Available after waiting concurrency " + taskSchedulerConfig.getConcurrency());

                    }
                    final Task taskToExecute = getTaskToExecute();
                    System.out.println("Task to execute " + taskToExecute);
                    if (taskToExecute == null) {
                        System.out.print("No task to execute at the moment, waiting for 1 second\n");
                        Thread.sleep(1000);
                        continue;
                    }
                    taskSchedulerConfig.decrementConcurrency();
                    new TaskExecuter(taskToExecute, taskSchedulerConfig).start();
                    System.out.println();
                }
            }
        } catch (InterruptedException e) {
            throw new RuntimeException(e);
        }
    }

    private Task getTaskToExecute() {
        System.out.println("Scheduled tasks: " + scheduledTasks);
        System.out.println("Ad Hoc tasks: " + tasks);
        if (this.scheduledTasks.isEmpty() && this.tasks.isEmpty()) {
            System.out.println("Both empty");
            return null;
        }
        final long currentTime = System.currentTimeMillis();
        if (this.tasks.isEmpty()) {
            Task nextScheduledTask = scheduledTasks.peek();
            if (nextScheduledTask != null && currentTime >= nextScheduledTask.getScheduledTime()) {
                return scheduledTasks.poll();
            }
            return null;
        }

        if (this.scheduledTasks.isEmpty()) {
            System.out.println("Only tasks");
            return tasks.poll();
        }

        Task nextAdHocTask = tasks.peek();
        Task nextScheduledTask = scheduledTasks.peek();
        System.out.println("Current time " + currentTime);
        System.out.println(currentTime >= nextScheduledTask.getScheduledTime());
        System.out.println(currentTime + nextAdHocTask.getDuration() * 1000L < nextScheduledTask.getScheduledTime());


        // Scheduled task is ready and takes precedence over ad-hoc tasks
        if (currentTime >= nextScheduledTask.getScheduledTime()) {
            return scheduledTasks.poll();
        }

        // Ad-hoc task can be executed before the next scheduled task
        if (currentTime + nextAdHocTask.getDuration() * 1000L < nextScheduledTask.getScheduledTime()) {
            return tasks.poll();
        }

        return null; // blocks the task scheduler on the scheduled task even if concurrency is available for ad hoc tasks to run
    }
}

