public class TaskSchedulerConfig {
    private int concurrency;

    public TaskSchedulerConfig(final int concurrency) {
        this.concurrency = concurrency;
    }

    public void decrementConcurrency() {
        System.out.println("Decreasing concurrency");
        this.concurrency--;

    }

    public void incrementConcurrency() {
        System.out.println("Increasing concurrency");
        this.concurrency++;
    }

}

